    ///
    /// "Underscored_input_String_is_turned_into_sentence".Humanize()
    ///   => "Underscored input string is turned into sentence"
    ///
    /// "HTMLParser".Humanize() => "HTML parser"
    /// </code>
    /// </example>
    public static string Humanize(this string input)
    {
        if (string.IsNullOrWhiteSpace(input))
        {
            return input;
        }

        // Handle underscore/dash separated — cheap char scan before any regex
        if (input.Contains('_') || input.Contains('-'))
        {
            return FromUnderscoreDashSeparatedWords(input);
        }

        // Check if the input is entirely whitespace/tab characters (no words to extract)
        if (IsAllSpacingChars(input))
        {
            return input;
        }

        return FromPascalCase(input);
    }

    /// <summary>
    /// Returns true if every character is a Unicode space separator or tab.
    /// Replaces the previous regex-based FreestandingSpacingCharRegex check.
    /// </summary>
    private static bool IsAllSpacingChars(string input)
    {
        foreach (var c in input)
        {
            if (c != '\t' && char.GetUnicodeCategory(c) != System.Globalization.UnicodeCategory.SpaceSeparator)
            {
                return false;
            }
        }
        return true;
    }

    private static readonly char[] SeparatorChars = ['_', '-'];

    /// <summary>
    /// Converts a string from underscore or dash separation to a human-readable form.
    /// </summary>
    /// <param name="input">The underscore or dash separated string.</param>
    /// <returns>A space-separated human-readable string.</returns>
    internal static string FromUnderscoreDashSeparatedWords(string input) =>
        string.Join(" ", input.Split(SeparatorChars));

    /// <summary>
    /// Returns true if every character in the span is an uppercase letter.
    /// Avoids the LINQ <c>.All(char.IsUpper)</c> allocation on strings.
    /// </summary>
    private static bool IsAllUpper(ReadOnlySpan<char> value)
    {
        foreach (var c in value)
        {
            if (!char.IsUpper(c))
            {
                return false;
            }
        }
        return true;
    }

