        var matches = PascalCaseWordPartsRegex().Matches(input);
        if (matches.Count == 0)
        {
            return input;
        }

        // Pre-calculate total length to size the buffer once
        int totalLength = matches.Count - 1; // spaces between words
        for (int i = 0; i < matches.Count; i++)
        {
            totalLength += matches[i].Length;
        }

        var buffer = totalLength <= 256
            ? stackalloc char[totalLength]
            : new char[totalLength];

        int pos = 0;
        bool allUpperAndSpaces = true;
        bool hasMultipleWords = matches.Count > 1;

        for (int i = 0; i < matches.Count; i++)
        {
            if (i > 0)
            {
                buffer[pos++] = ' ';
            }

            var match = matches[i];
            ReadOnlySpan<char> value = input.AsSpan(match.Index, match.Length);
            bool isUpper = IsAllUpper(value);

            bool keepUpper = isUpper &&
                (value.Length > 1
                    || (match.Index > 0 && input[match.Index - 1] == ' ')
                    || (value.Length == 1 && value[0] == 'I'));

            if (keepUpper)
            {
                value.CopyTo(buffer[pos..]);
            }
            else
            {
                allUpperAndSpaces = false;
                for (int j = 0; j < value.Length; j++)
                {
                    buffer[pos + j] = char.ToLowerInvariant(value[j]);
                }
            }
            pos += value.Length;
        }

        // If every word was kept uppercase and there are multiple words, lowercase everything
        if (allUpperAndSpaces && hasMultipleWords)
        {
            for (int i = 0; i < buffer.Length; i++)
            {
                if (buffer[i] != ' ')
                {
                    buffer[i] = char.ToLowerInvariant(buffer[i]);
                }
            }
        }

        // Capitalize first character
        if (buffer.Length > 0)
        {
            buffer[0] = char.ToUpperInvariant(buffer[0]);
        }

        return new string(buffer);
    }

