/// <summary>
/// Transforms a string using a single transformer.
/// Avoids the params array allocation for the common single-transformer case.
/// </summary>
public static string Transform(this string input, IStringTransformer transformer) =>
    transformer.Transform(input);

/// <summary>
/// Transforms a string using the provided transformers, applied in order.
