7. /// and PascalCase/camelCase representations.
8. /// </summary>
9. public static partial class StringReadabilityExtensions
10. {
11. #if NET7_0_OR_GREATER
12.     [GeneratedRegex(@"[\p{Lu}]+(?=\p{Lu}[\p{Ll}])|[\p{Lu}]?[\p{Ll}]+|\d+")]
13.     private static partial Regex PascalCaseWordPartsRegexGenerated();
14. 
15.     private static Regex PascalCaseWordPartsRegex() => PascalCaseWordPartsRegexGenerated();
16. #else
17.     private static readonly Regex PascalCaseWordPartsRegexField =
18.         new(@"[\p{Lu}]+(?=\p{Lu}[\p{Ll}])|[\p{Lu}]?[\p{Ll}]+|\d+", RegexOptions.Compiled);
19. 
20.     private static Regex PascalCaseWordPartsRegex() => PascalCaseWordPartsRegexField;
21. #endif
