23.     /// <summary>
24.     /// Converts a machine-readable string (PascalCase, camelCase, snake_case, kebab-case)
25.     /// to a human-readable form with spaces between words.
26.     /// </summary>
27.     /// <param name="input">The string to humanize.</param>
28.     /// <returns>A human-readable version of the input string.</returns>
29.     /// <example>
30.     /// <code>
31.     /// "PascalCaseInputStringIsTurnedIntoSentence".Humanize()
32.     ///   => "Pascal case input string is turned into sentence"
33.     ///
34.     /// "Underscored_input_String_is_turned_into_sentence".Humanize()
35.     ///   => "Underscored input string is turned into sentence"
36.     ///
37.     /// "HTMLParser".Humanize() => "HTML parser"
38.     /// </code>
39.     /// </example>
40.     public static string Humanize(this string input)
41.     {
42.         if (string.IsNullOrWhiteSpace(input))
43.         {
44.             return input;
45.         }
46. 
47.         // Handle underscore/dash separated — cheap char scan before any regex
48.         if (input.Contains('_') || input.Contains('-'))
49.         {
50.             return FromUnderscoreDashSeparatedWords(input);
51.         }
52. 
53.         // Check if the input is entirely whitespace/tab characters (no words to extract)
54.         if (IsAllSpacingChars(input))
55.         {
56.             return input;
57.         }
58. 
59.         return FromPascalCase(input);
60.     }
61. 
62.     /// <summary>
63.     /// Returns true if every character is a Unicode space separator or tab.
64.     /// Replaces the previous regex-based FreestandingSpacingCharRegex check.
65.     /// </summary>
66.     private static bool IsAllSpacingChars(string input)
67.     {
68.         foreach (var c in input)
69.         {
70.             if (c != '\t' && char.GetUnicodeCategory(c) != System.Globalization.UnicodeCategory.SpaceSeparator)
71.             {
72.                 return false;
73.             }
74.         }
75.         return true;
76.     }
77. 
78.     private static readonly char[] SeparatorChars = ['_', '-'];
79. 
80.     /// <summary>
81.     /// Converts a string from underscore or dash separation to a human-readable form.
82.     /// </summary>
83.     /// <param name="input">The underscore or dash separated string.</param>
84.     /// <returns>A space-separated human-readable string.</returns>
85.     internal static string FromUnderscoreDashSeparatedWords(string input) =>
86.         string.Join(" ", input.Split(SeparatorChars));
87. 
88.     /// <summary>
89.     /// Returns true if every character in the span is an uppercase letter.
90.     /// Avoids the LINQ <c>.All(char.IsUpper)</c> allocation on strings.
91.     /// </summary>
92.     private static bool IsAllUpper(ReadOnlySpan<char> value)
93.     {
94.         foreach (var c in value)
95.         {
96.             if (!char.IsUpper(c))
97.             {
98.                 return false;
99.             }
100.         }
101.         return true;
102.     }
103. 
104.     /// <summary>
105.     /// Converts a PascalCase or camelCase string to a human-readable form.
106.     /// Preserves acronyms (consecutive uppercase letters) as-is.
107.     /// </summary>
108.     /// <param name="input">The PascalCase string to convert.</param>
109.     /// <returns>A space-separated human-readable string.</returns>
110.     internal static string FromPascalCase(string input)
111.     {
112.         var matches = PascalCaseWordPartsRegex().Matches(input);
113.         if (matches.Count == 0)
114.         {
115.             return input;
116.         }
117. 
118.         // Pre-calculate total length to size the buffer once
119.         int totalLength = matches.Count - 1; // spaces between words
120.         for (int i = 0; i < matches.Count; i++)
121.         {
122.             totalLength += matches[i].Length;
123.         }
124. 
125.         var buffer = totalLength <= 256
126.             ? stackalloc char[totalLength]
127.             : new char[totalLength];
128. 
129.         int pos = 0;
130.         bool allUpperAndSpaces = true;
131.         bool hasMultipleWords = matches.Count > 1;
132. 
133.         for (int i = 0; i < matches.Count; i++)
134.         {
135.             if (i > 0)
136.             {
137.                 buffer[pos++] = ' ';
138.             }
139. 
140.             var match = matches[i];
141.             ReadOnlySpan<char> value = input.AsSpan(match.Index, match.Length);
142.             bool isUpper = IsAllUpper(value);
143. 
144.             bool keepUpper = isUpper &&
145.                 (value.Length > 1
146.                     || (match.Index > 0 && input[match.Index - 1] == ' ')
147.                     || (value.Length == 1 && value[0] == 'I'));
148. 
149.             if (keepUpper)
150.             {
151.                 value.CopyTo(buffer[pos..]);
152.             }
153.             else
154.             {
155.                 allUpperAndSpaces = false;
156.                 for (int j = 0; j < value.Length; j++)
157.                 {
158.                     buffer[pos + j] = char.ToLowerInvariant(value[j]);
159.                 }
160.             }
161.             pos += value.Length;
162.         }
163. 
164.         // If every word was kept uppercase and there are multiple words, lowercase everything
165.         if (allUpperAndSpaces && hasMultipleWords)
166.         {
167.             for (int i = 0; i < buffer.Length; i++)
168.             {
169.                 if (buffer[i] != ' ')
170.                 {
171.                     buffer[i] = char.ToLowerInvariant(buffer[i]);
172.                 }
173.             }
174.         }
175. 
176.         // Capitalize first character
177.         if (buffer.Length > 0)
178.         {
179.             buffer[0] = char.ToUpperInvariant(buffer[0]);
180.         }
181. 
182.         return new string(buffer);
183.     }
184. 
185.     /// <summary>
186.     /// Concatenates two <see cref="ReadOnlySpan{T}"/> of <see cref="char"/> into a new string.
187.     /// Uses efficient span-based concatenation to avoid intermediate allocations.
188.     /// </summary>
189.     /// <param name="first">The first span of characters.</param>
190.     /// <param name="second">The second span of characters.</param>
191.     /// <returns>A new string containing the concatenated characters.</returns>
192.     internal static string Concat(ReadOnlySpan<char> first, ReadOnlySpan<char> second)
193.     {
194.         return string.Concat(first, second);
195.     }
196. 
197.     /// <summary>
198.     /// Concatenates a single character with a <see cref="ReadOnlySpan{T}"/> of characters.
199.     /// </summary>
200.     /// <param name="c">The character to prepend.</param>
201.     /// <param name="rest">The remaining characters.</param>
202.     /// <returns>A new string with the character prepended.</returns>
203.     internal static string Concat(char c, ReadOnlySpan<char> rest)
204.     {
205.         Span<char> buffer = stackalloc char[1 + rest.Length];
206.         buffer[0] = c;
207.         rest.CopyTo(buffer[1..]);
208.         return new string(buffer);
209.     }
210. }
